parameters.functionCode:
const message = $json.body.message.text;
const senderId = $json.body.message.from;

// Simula a extração do nome do cliente se for a primeira interação ou se o agente perguntou
let clientName = null;
if (message.toLowerCase().includes('meu nome é')) {
  const match = message.match(/meu nome é (.*)/i);
  if (match && match[1]) {
    clientName = match[1].trim();
  }
}

return [{
  json: {
    senderId: senderId,
    message: message,
    clientName: clientName,
    // Adicione aqui outros dados que você extrairia do webhook do WhatsApp
    // Ex: tipo de mensagem, mídia, etc.
  }
}];

const clientData = $node["Consultar Cliente Supabase"].json.data[0];
const message = $node["Extrair Dados WhatsApp"].json.message;
const senderId = $node["Extrair Dados WhatsApp"].json.senderId;

let prompt = `Você é um assistente de vendas de autopeças chamado João, muito amistoso, prestativo e cordial. Seu objetivo é atender o cliente de forma humanizada, nada robótica. Sempre pergunte o modelo e ano do veículo para garantir a compatibilidade da peça, mas continue o atendimento mesmo sem essa informação. Você também pode sugerir peças paralelas ou alternativas compatíveis.\n\nInformações do Cliente: ${clientData ? `Nome: ${clientData.nome}, Tipo: ${clientData.tipo}` : 'Novo Cliente'}\n\nÚltima Mensagem do Cliente: ${message}\n\nCom base nas informações acima, qual seria a melhor resposta para o cliente? Se for a primeira interação, comece perguntando o nome do cliente.`;

return [{
  json: {
    prompt: prompt,
    senderId: senderId,
    clientData: clientData || null,
    message: message
  }
}];

const claudeResponse = $node["Chamar Claude (Lovable Pro)"].json.body.response;
const originalMessage = $node["Preparar Prompt para Claude"].json.message;

// Simula a extração da peça, modelo e ano da resposta do Claude ou da mensagem original
let requestedPart = null;
let vehicleModel = null;
let vehicleYear = null;

// Lógica simplificada para protótipo
if (originalMessage.toLowerCase().includes('pastilha de freio')) {
  requestedPart = 'Pastilha de Freio Dianteira';
}
if (originalMessage.toLowerCase().includes('filtro de oleo')) {
  requestedPart = 'Filtro de Óleo';
}
if (originalMessage.toLowerCase().includes('amortecedor')) {
  requestedPart = 'Amortecedor Traseiro';
}

if (originalMessage.toLowerCase().includes('palio')) {
  vehicleModel = 'Fiat Palio';
  vehicleYear = '2010-2015';
}
if (originalMessage.toLowerCase().includes('gol')) {
  vehicleModel = 'VW Gol G5';
  vehicleYear = '2008-2012';
}

return [{
  json: {
    claudeResponse: claudeResponse,
    requestedPart: requestedPart,
    vehicleModel: vehicleModel,
    vehicleYear: vehicleYear,
    senderId: $node["Preparar Prompt para Claude"].json.senderId,
    clientData: $node["Preparar Prompt para Claude"].json.clientData
  }
}];

const requestedPart = $json.requestedPart;
const vehicleModel = $json.vehicleModel;
const vehicleYear = $json.vehicleYear;

const simulatedStock = [
  {
    "id_peca": "P001",
    "nome_peca": "Pastilha de Freio Dianteira",
    "marca": "Bosch",
    "compatibilidade": ["Fiat Palio 2010-2015", "Fiat Siena 2010-2015", "VW Gol G5 2008-2012"],
    "disponibilidade": 10,
    "preco": 120.50,
    "url_foto": "https://i.imgur.com/example1.jpg",
    "tipo_peca": "Original",
    "alternativas_compativeis": ["P002", "P003"]
  },
  {
    "id_peca": "P002",
    "nome_peca": "Pastilha de Freio Dianteira",
    "marca": "Fras-le",
    "compatibilidade": ["Fiat Palio 2010-2015", "Fiat Siena 2010-2015", "VW Gol G5 2008-2012"],
    "disponibilidade": 5,
    "preco": 85.00,
    "url_foto": "https://i.imgur.com/example2.jpg",
    "tipo_peca": "Paralela de Qualidade",
    "alternativas_compativeis": ["P001", "P003"]
  },
  {
    "id_peca": "P003",
    "nome_peca": "Pastilha de Freio Dianteira",
    "marca": "Paralela Genérica",
    "compatibilidade": ["Fiat Palio 2010-2015", "Fiat Siena 2010-2015", "VW Gol G5 2008-2012"],
    "disponibilidade": 20,
    "preco": 50.00,
    "url_foto": "https://i.imgur.com/example3.jpg",
    "tipo_peca": "Paralela Econômica",
    "alternativas_compativeis": ["P001", "P002"]
  },
  {
    "id_peca": "P004",
    "nome_peca": "Filtro de Óleo",
    "marca": "Mann Filter",
    "compatibilidade": ["Ford Ka 2015-2020", "Ford Fiesta 2015-2020"],
    "disponibilidade": 15,
    "preco": 45.00,
    "url_foto": "https://i.imgur.com/example4.jpg",
    "tipo_peca": "Original",
    "alternativas_compativeis": []
  },
  {
    "id_peca": "P005",
    "nome_peca": "Amortecedor Traseiro",
    "marca": "Cofap",
    "compatibilidade": ["Chevrolet Onix 2013-2019", "Chevrolet Prisma 2013-2019"],
    "disponibilidade": 8,
    "preco": 280.00,
    "url_foto": "https://i.imgur.com/example5.jpg",
    "tipo_peca": "Original",
    "alternativas_compativeis": []
  }
];

let foundParts = [];
if (requestedPart) {
  foundParts = simulatedStock.filter(part => 
    part.nome_peca.toLowerCase().includes(requestedPart.toLowerCase()) &&
    (!vehicleModel || part.compatibilidade.some(comp => comp.toLowerCase().includes(vehicleModel.toLowerCase()))) &&
    (!vehicleYear || part.compatibilidade.some(comp => comp.includes(vehicleYear)))
  );
}

return [{
  json: {
    ...$json,
    foundParts: foundParts
  }
}];

const claudeResponse = $json.claudeResponse;
const foundParts = $json.foundParts;
const senderId = $json.senderId;
const clientData = $json.clientData;

let finalMessage = claudeResponse;
let photos = [];

if (foundParts.length > 0) {
  finalMessage += "\n\nEncontrei as seguintes opções para você:";
  foundParts.forEach(part => {
    finalMessage += `\n- ${part.nome_peca} (${part.marca}) - R$ ${part.preco.toFixed(2)} - Disponibilidade: ${part.disponibilidade > 0 ? part.disponibilidade + ' em estoque' : 'Esgotado'}. Tipo: ${part.tipo_peca}.`;
    if (part.url_foto) {
      photos.push(part.url_foto);
    }
  });

  // Lógica para sugerir alternativas
  const firstPart = foundParts[0];
  if (firstPart.alternativas_compativeis && firstPart.alternativas_compativeis.length > 0) {
    finalMessage += "\n\nTambém posso sugerir algumas alternativas compatíveis:";
    firstPart.alternativas_compativeis.forEach(altId => {
      const altPart = $node["Simular Busca Estoque"].json.simulatedStock.find(p => p.id_peca === altId); // Acessa o estoque simulado para detalhes
      if (altPart) {
        finalMessage += `\n- ${altPart.nome_peca} (${altPart.marca}) - R$ ${altPart.preco.toFixed(2)} (${altPart.tipo_peca})`;
      }
    });
  }
} else if ($json.requestedPart) {
  finalMessage += "\n\nDesculpe, não encontrei a peça que você procura em nosso estoque no momento. Posso verificar outras opções ou marcas para você?";
}

// Lógica para cobrança (exemplo: se a mensagem do Claude indicar uma compra)
let offerPayment = false;
if (claudeResponse.toLowerCase().includes('gostaria de finalizar a compra') || claudeResponse.toLowerCase().includes('posso gerar o link de pagamento')) {
  offerPayment = true;
}

return [{
  json: {
    senderId: senderId,
    finalMessage: finalMessage,
    photos: photos,
    offerPayment: offerPayment,
    clientData: clientData
  }
}];

